import { invokeWithTimeout as invoke } from "@/lib/tauriInvoke";

// Types mirror src-tauri/src/engine/director.rs. Canonical bindings are
// generated by ts-rs on `cargo test` under src/lib/bindings/ — once they
// land we can switch to importing from there.

export type DirectorSeverity = 'info' | 'warning' | 'error';

export type DirectorCategory =
  | 'prompt'
  | 'health'
  | 'triggers'
  | 'credentials'
  | 'memory'
  | 'usefulness';

export interface DirectorReport {
  evaluatedPersonas: number;
  verdictsEmitted: number;
  personasSkippedNoExecutions: number;
  generatedAt: string;
}

export interface DirectorVerdictRow {
  reviewId: string;
  personaId: string;
  severity: string;
  category: string;
  title: string;
  description: string | null;
  rationale: string | null;
  suggestedActions: string[];
  status: string;
  createdAt: string;
  executionId: string;
}

// Portfolio analytics (command center). Mirrors the Rust structs in
// engine/director.rs; ts-rs also exports canonical bindings under
// src/lib/bindings/ — these inline shapes match the file's existing convention.

export interface ModelValueShare {
  model: string;
  executions: number;
  costUsd: number;
  valueDelivered: number;
}

export interface ValueRollup {
  periodDays: number;
  totalExecutions: number;
  assessedExecutions: number;
  valueDelivered: number;
  partial: number;
  preconditionFailed: number;
  noInputAvailable: number;
  unknown: number;
  valueDeliveredRate: number;
  totalCostUsd: number;
  costPerValueDelivered: number | null;
  models: ModelValueShare[];
}

export interface DirectorRosterEntry {
  personaId: string;
  name: string;
  icon: string | null;
  color: string | null;
  latestScore: number | null;
  scoreTrend: number[];
  valueDeliveredRate: number;
  totalExecutions: number;
  lastReviewedAt: string | null;
}

export interface DirectorScoreBand {
  score: number;
  count: number;
}

export interface DirectorPortfolio {
  rollup: ValueRollup;
  roster: DirectorRosterEntry[];
  scoreDistribution: DirectorScoreBand[];
  inScope: number;
  reviewed: number;
  unreviewed: number;
  avgScore: number | null;
  periodDays: number;
}

export async function getDirectorPersonaId(): Promise<string> {
  return invoke<string>('get_director_persona_id');
}

/** Portfolio analytics for the command center (fleet rollup + in-scope roster + score distribution). */
export async function getDirectorPortfolio(days?: number): Promise<DirectorPortfolio> {
  return invoke<DirectorPortfolio>('get_director_portfolio', { days: days ?? null });
}

// Phase 2 runs the Director persona through the execution runner and polls it
// to completion, so a single evaluation can take minutes (backend ceiling is
// 360s). Use generous timeouts well above the default 90s.
const DIRECTOR_RUN_TIMEOUT_MS = 420_000; // 7 min — one target
const DIRECTOR_BATCH_TIMEOUT_MS = 1_800_000; // 30 min — sequential over many

export async function runDirectorOnPersona(personaId: string): Promise<number> {
  return invoke<number>('run_director_on_persona', { personaId }, { timeoutMs: DIRECTOR_RUN_TIMEOUT_MS });
}

export async function runDirectorBatch(maxPersonas?: number): Promise<DirectorReport> {
  return invoke<DirectorReport>(
    'run_director_batch',
    { maxPersonas: maxPersonas ?? null },
    { timeoutMs: DIRECTOR_BATCH_TIMEOUT_MS },
  );
}

export async function listDirectorVerdicts(personaId?: string): Promise<DirectorVerdictRow[]> {
  return invoke<DirectorVerdictRow[]>('list_director_verdicts', {
    personaId: personaId ?? null,
  });
}

/**
 * Recent Director scores per persona, oldest→newest. Personas with no scored
 * executions return `[]`. Powers the verdict-trend sparkline on the personas
 * table — one batched call covers every visible row.
 */
export async function listDirectorScoreTrends(
  personaIds: string[],
  limit?: number,
): Promise<Record<string, number[]>> {
  if (personaIds.length === 0) return {};
  return invoke<Record<string, number[]>>('list_director_score_trends', {
    personaIds,
    limit: limit ?? null,
  });
}

/** Whether the Director uses the Obsidian Brain vault as long-term memory. */
export async function getDirectorBrainEnabled(): Promise<boolean> {
  return invoke<boolean>('get_director_brain_enabled');
}

/** Toggle the Director's Brain long-term memory (gated on a configured vault). */
export async function setDirectorBrainEnabled(enabled: boolean): Promise<void> {
  return invoke<void>('set_director_brain_enabled', { enabled });
}
